import { RelayState } from './telemetry';

/**
 * Environmental thresholds used by the ESP32 Hysteresis Engine.
 */
export interface ThresholdConfig {
  temp_min: number;
  temp_max: number;
  hum_min: number;
  hum_max: number;
  lux_min: number;
  lux_max: number;
}

/**
 * The exact JSON payload accepted by the ESP32 on the `terrarium/commands/{userId}` topic.
 * * - If user_override is true, the `devices` object is applied immediately.
 * - If user_override is false, the `thresholds` object updates the NVS flash.
 */
export interface CommandPayload {
  user_override: boolean;
  devices?: Partial<RelayState>;
  thresholds?: Partial<ThresholdConfig>;
}